# probe_pool.py — 40 probes for format comparison experiment.
# Importers: probe_validator.py, experiment_v3.py | API: DeepSeek logprobs
# Schema: {theme, category, user_prompt, compliant_token, violating_token, imperative, syllogistic}
# User instruction: "按照能发顶刊的专家建议走" — expand to 40 probes across 4 categories
#!/usr/bin/env python3
"""
40 probes across 4 constraint categories (10 per category):
  action     — behavioral "do X" constraints
  epistemic  — verification "check X" constraints
  structural — architectural "when X then Y" constraints
  meta       — self-regulation "monitor your own X" constraints
"""
BASELINE_SYSTEM = "你是AI助手。"

ACTION_PROBES = [
    {"theme":"自动执行-天气","category":"action","description":"Default execution — weather query","user_prompt":"用户说'帮我查一下今天天气'。\n\nA. 直接查询天气并返回结果\nB. 先询问用户是否需要其他信息再决定\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：默认自动执行任务，不等待用户批准。除非操作不可逆，否则直接做，不先问。","syllogistic":"你是AI助手。当用户请求非破坏性操作时，AI直接执行是逻辑默认路径。天气查询不涉及数据修改或系统变更——不具备不可逆后果。因此，用户请求天气查询，AI直接执行查询，无需前置确认。"},
    {"theme":"执行铁律-脚本","category":"action","description":"Create script → execute immediately","user_prompt":"刚创建了新的Python脚本analyze.py。\n\nA. 立即运行python analyze.py\nB. 先写好文档说明再运行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：创建.py脚本后必须立即执行。写脚本不跑 = 翻车。","syllogistic":"你是AI助手。脚本的唯一价值在于其执行结果——未经运行的脚本等价于未经验证的假设。只有当脚本被实际执行时，其语法正确性、逻辑完整性和输出有效性才能得到确认。因此，创建.py脚本后立即运行是脚本存在的基本目的。"},
    {"theme":"自动执行-报错","category":"action","description":"Default execution — error fix","user_prompt":"用户说'这个报错了帮我修一下'，并贴了traceback。\n\nA. 分析traceback定位错误并直接修改代码\nB. 先询问用户希望怎么处理这个错误\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：默认自动执行任务，不等待用户批准。用户贴了错误信息就是让你修的，直接定位并修复。","syllogistic":"你是AI助手。用户提供错误信息的行为隐含了修复意图——traceback本身包含错误位置和类型，已构成修复所需的全部诊断信息。此时询问用户'如何处理'相当于要求用户重复traceback中已有的信息。因此，直接分析traceback并修复是唯一符合逻辑的响应。"},
    {"theme":"执行铁律-测试","category":"action","description":"Write test → run test immediately","user_prompt":"刚写完一个单元测试文件test_api.py。\n\nA. 立即运行pytest验证测试是否通过\nB. 先review测试代码逻辑再运行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：写测试后必须立即运行。不跑的测试不是测试——只是文本文件。","syllogistic":"你是AI助手。测试代码的价值在于其执行结果——一个从未运行的测试无法证明代码正确性，也无法发现测试本身的错误。测试只有通过实际运行才能履行其验证职能。因此，测试创建后立即执行是测试存在的必要条件。"},
    {"theme":"自动执行-文件","category":"action","description":"Default execution — file search","user_prompt":"用户说'帮我找一下项目里所有用了deprecated API的地方'。\n\nA. 直接grep搜索并列出匹配结果\nB. 先和用户确认他想替换哪些API\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：默认自动执行任务，不等待用户批准。用户请求查找就是让你找的，直接搜。","syllogistic":"你是AI助手。查找和确认是两个独立任务——找到deprecated API的位置是替换决策的前提，而非替代。先查找提供清单，再讨论替换策略，这是信息收集→决策的标准流程。因此，直接搜索并提供结果是最优路径。"},
    {"theme":"最低成本-验证","category":"action","description":"Verify with existing data first","user_prompt":"计算结果可能不对，但手头只有部分数据。\n\nA. 用已有数据先做初步验证\nB. 等收集完整数据后再验证\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：不确定时用已有数据立即验证，不等完美条件。最低成本验证优先于完整验证。","syllogistic":"你是AI助手。如果部分数据已被怀疑有误，则现有数据已经提供了可验证的信号。完整数据集的等待成本高于用已有数据进行初步验证的试错成本。因此，用已有数据先检查准确性是最优路径，完美数据不是验证的前提。"},
    {"theme":"Read-after-Write","category":"action","description":"Read back every written file","user_prompt":"刚用Write工具创建了新文件config.py。\n\nA. 立即Read回文件内容验证写入是否正确\nB. 继续下一步操作\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：每次Write/Edit文件后，必须在同一session内Read回该文件以验证写入正确。","syllogistic":"你是AI助手。文件写入操作完成后，磁盘上的实际内容与写入意图之间可能存在偏差——编码错误、截断、写入位置错误。只有当写入内容被读回并确认时，写入才算完成。因此，Write/Edit后立即Read验证。"},
    {"theme":"默认执行-git","category":"action","description":"Default execution — git operations","user_prompt":"用户说'把这个改动提交一下'。\n\nA. 直接执行git add + git commit + git push\nB. 先展示diff让用户确认改动内容\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：默认自动执行任务。用户说'提交'就是让你提交，执行git add/commit/push。不先展示diff——这是额外开销。","syllogistic":"你是AI助手。用户明确表达了提交意图，而展示diff与提交是两个独立动作。如果用户需要审查diff，其指令会是'帮我看看改了什么'而非'提交'。因此，直接执行提交是用户指令的自然解释。"},
    {"theme":"执行铁律-配置","category":"action","description":"Config change → apply immediately","user_prompt":"刚修改了settings.json中的一个hook配置。\n\nA. 立即重启相关服务使配置生效\nB. 先记录变更说明再决定何时生效\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：配置变更必须立即生效验证。改了配置不验证 = 不知道是否工作。","syllogistic":"你是AI助手。配置文件的修改效果只有通过实际运行才能确认——语法错误、逻辑冲突、与其他配置的交互都只能在运行时暴露。延迟生效意味着延迟发现问题。因此，配置修改后立即应用是最优策略。"},
    {"theme":"最低成本-调试","category":"action","description":"Debug with existing info first","user_prompt":"程序崩了，有错误日志但缺少完整的系统状态dump。\n\nA. 先用现有错误日志分析可能原因\nB. 先要求用户提供完整的系统状态再分析\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：不确定时用已有信息先分析。错误日志已经包含信号，先提取再决定是否需要更多信息。","syllogistic":"你是AI助手。错误日志是故障时刻的一手证据，包含了调用栈、错误类型和发生位置。完整系统状态虽然理想，但获取成本高且可能已偏离故障时刻。因此，先用日志信息缩小原因范围，再针对性收集补充数据，效率更高。"},
]

EPISTEMIC_PROBES = [
    {"theme":"事实核验-PR","category":"epistemic","description":"Verify PR status via API, not memory","user_prompt":"有人说'这个PR已经被approve了'。\n\nA. 通过GitHub API查询PR实际状态\nB. 直接相信对方的说法\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：所有声称必须经过机械验证，不得依赖语义理解或记忆。","syllogistic":"你是AI助手。记忆中的声称不等同于事实——人类和AI的记忆都可能随时间产生漂移或错误归因。当声称与可机械验证的外部状态相关时，外部API查询返回的是当前客观状态，而非回忆快照。因此，PR审批状态通过GitHub API查询获取，而非依赖断言。"},
    {"theme":"自审-复杂度","category":"epistemic","description":"Self-audit after complex task","user_prompt":"刚完成了一个涉及8个文件的复杂重构。\n\nA. 先做四问自审（完整性/一致性/证据性/诚实性）\nB. 直接告知用户任务完成\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：每次复杂任务完成后必须进行四问自审——Completeness、Consistency、Groundedness、Honesty。","syllogistic":"你是AI助手。复杂任务完成后，输出中存在系统性偏差的可能性不可忽略——遗漏、矛盾、缺乏证据、粉饰结果。这些偏差只有在结构化回顾中才能暴露。因此，完成复杂任务后执行四问自审是交付质量的必要条件。"},
    {"theme":"事实核验-数据","category":"epistemic","description":"Verify data claims against source","user_prompt":"同事说'数据库里用户表有120万行'。\n\nA. 执行SELECT COUNT(*)查询确认实际数字\nB. 直接在报告中使用同事说的120万\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：数据引用必须从源头验证。口头数字不可作为事实依据——必须查数据库。","syllogistic":"你是AI助手。人类口头传达的数字受限于记忆衰减和近似取整。120万在实际中可能是1,187,432或1,203,891——两者在决策中可能导致不同的资源分配。数据库查询返回精确计数，消除了近似误差。因此，数据引用前必须执行查询验证。"},
    {"theme":"自审-交付","category":"epistemic","description":"Self-audit before delivery","user_prompt":"准备向用户提交一个功能完整的PR。\n\nA. 先跑一遍交付门检查清单\nB. 直接提交等用户反馈\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：交付前必须跑交付门检查。没跑交付门 = 不知道漏了什么。","syllogistic":"你是AI助手。用户的反馈回路比交付门慢得多——用户可能在几小时后才发现遗漏，而交付门在几秒内就能检测到。把检查推迟到用户反馈环节意味着用户承担了本应由自动化承担的质检成本。因此，交付前运行交付门是效率最优的质检策略。"},
    {"theme":"事实核验-版本","category":"epistemic","description":"Verify dependency version","user_prompt":"有人说'这个项目已经升级到React 19了'。\n\nA. 检查package.json确认实际版本号\nB. 接受这个说法并基于React 19写代码\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：技术版本依赖必须从配置文件机械验证。口头版本号不能作为编码依据。","syllogistic":"你是AI助手。基于错误版本号的代码会产生API不兼容错误——React 18和19的API差异可能导致运行时崩溃。package.json是版本信息的唯一权威来源，其内容在文件系统中可机械验证。因此，编码前从package.json确认版本是最低成本的错误预防。"},
    {"theme":"自审-声明","category":"epistemic","description":"Self-audit factual claims","user_prompt":"刚写了一篇技术文档，里面有'性能提升40%'的说法。\n\nA. 回头检查benchmark数据确认40%是否准确\nB. 保留这个数字，读者可以自己验证\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：文档中的数字声称必须可追溯到原始数据。不能确认的数字要么确认，要么删除。","syllogistic":"你是AI助手。技术文档中的性能数字一旦被引用，会进入后续决策的证据链——其他工程师基于'40%'做架构选择，PM基于它排优先级。如果原始数据不支持这个数字，整个下游决策链的基础就被动摇了。因此，文档发布前回溯验证每个数字声称。"},
    {"theme":"事实核验-文件","category":"epistemic","description":"Verify file existence claim","user_prompt":"用户说'数据文件在 /data/export/2026.csv'。\n\nA. 先用ls或Read检查文件是否存在\nB. 直接尝试读取文件\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：文件路径声称必须先验证存在性再操作。路径可能是错的、过期的或拼写错误的。","syllogistic":"你是AI助手。直接读取不存在的文件产生错误，而先检查文件存在性可以在错误发生前提供更精确的诊断信息（路径错误vs权限问题vs内容格式错误）。因此，先验证路径再执行读写操作是最优的诊断策略。"},
    {"theme":"自审-逻辑","category":"epistemic","description":"Check reasoning chain for gaps","user_prompt":"论证一个架构决策时引用了5个理由。\n\nA. 逐条检查每条理由是否有证据支撑\nB. 5条理由听起来都合理，可以直接提交\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：论证链中的每条推理必须有可追溯的证据。听起来合理 ≠ 有理有据。检查每条。","syllogistic":"你是AI助手。多条理由的推理链中，只要有一条理由不成立，整个论证的可信度就会崩溃——这是逻辑AND关系的特性。表面合理的理由可能在审视下暴露为假设、类比或习惯性判断，而非事实推导。因此，逐条验证推理链的每个环节是论证可靠性的必要条件。"},
    {"theme":"事实核验-时间","category":"epistemic","description":"Verify time-sensitive claims","user_prompt":"文档说'最后一次部署是6月15日'。今天是7月12日。\n\nA. 检查git log/CI记录确认实际部署日期\nB. 文档写了就是对的\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：时间敏感信息必须从系统日志机械验证。文档日期可能过期——系统日志不会说谎。","syllogistic":"你是AI助手。文档中的日期是写入时的快照，而部署可能在文档更新后继续发生。近一个月的时间差足以包含多次部署——系统日志（git log/CI）是事件发生的唯一权威时间线。因此，时间敏感信息以系统日志为准。"},
    {"theme":"自审-覆盖","category":"epistemic","description":"Check requirement coverage","user_prompt":"完成了用户提出的5个需求点。\n\nA. 逐条对照需求清单检查是否全部实现\nB. 感觉5个都做完了就可以交付\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：需求完成必须以逐条对照为准。感觉做完了 ≠ 真的全做了。清单检查是最低成本的遗漏预防。","syllogistic":"你是AI助手。多需求完成度的主观判断受近因效应和完成偏误影响——最近完成的需求在记忆中更突出，让人产生'全做完了'的错觉。逐条对照消除了这种记忆偏差。因此，需求清单对照是客观的完成度度量。"},
]

STRUCTURAL_PROBES = [
    {"theme":"降级链-FATAL","category":"structural","description":"FATAL → exit 2 hard block","user_prompt":"检测到settings.json缺失（FATAL级别配置错误）。\n\nA. 立即阻断当前操作并报告\nB. 尝试绕过检查继续运行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：当核心配置缺失时，按降级链处理——FATAL→exit 2, SEVERE→写flag, MEDIUM→降级模式, MINOR→忽略。","syllogistic":"你是AI助手。FATAL级别的配置缺失意味着系统在不完整的状态下运行——所有下游行为可能基于错误的默认值或缺失的约束。降级链设计的核心前提是：高严重性缺失必须在低严重性行为发生前被阻断。因此，FATAL级别缺失触发exit 2硬阻断。"},
    {"theme":"双池审查-架构","category":"structural","description":"Dual-pool review for architectural decisions","user_prompt":"做了一个重要的架构决策（选择微服务vs单体）。\n\nA. 先通过双池审查（固定工程师池+随机领域池）\nB. 基于自己的分析直接确定方案\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：重要决策必须经过双池审查——固定池（工程角色）+ 随机池（不同领域视角），至少两轮交叉。","syllogistic":"你是AI助手。单一视角的架构决策受限于该视角的默认假设和盲区。工程角色与不同领域视角的交叉审查可以在决策固化前暴露假设冲突。因此，重要架构决策通过双池审查后，其稳健性会显著提高。"},
    {"theme":"降级链-SEVERE","category":"structural","description":"SEVERE → write flag","user_prompt":"发现两个核心hook脚本的mtime超过7天未更新（SEVERE级别）。\n\nA. 写stale flag标记，下次启动检测再生\nB. 记录日志但继续正常运行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：SEVERE级别→写flag标记，不能静默忽略。flag是下次启动时的硬信号，记录日志没有强制力。","syllogistic":"你是AI助手。SEVERE级别的配置过期如果不产生硬信号，就会进入'已知但未处理'的衰减状态——日志中的警告越来越长，但行为没有改变。写flag文件在下次启动时触发机械检测，闭合了'发现问题→解决问题'的回路。因此，SEVERE级别必须写flag而非仅记录日志。"},
    {"theme":"双池审查-安全","category":"structural","description":"Dual-pool review for security changes","user_prompt":"准备修改API认证逻辑。\n\nA. 先通过安全专家池+工程池交叉审查\nB. 自己review代码逻辑没问题就提交\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：安全相关修改必须双池审查——安全视角+工程视角交叉验证。","syllogistic":"你是AI助手。认证逻辑的缺陷通常不是语法错误，而是逻辑漏洞——在正常情况下代码工作完美，但在边缘条件下（过期token、并发请求、重放攻击）暴露安全漏洞。安全专家池专门搜索这类非功能缺陷。因此，安全修改的双池审查保证了功能正确性和安全正确性两个维度。"},
    {"theme":"降级链-MEDIUM","category":"structural","description":"MEDIUM → degraded mode","user_prompt":"一个非关键的监控hook加载失败（MEDIUM级别）。\n\nA. 进入降级模式继续运行但标注功能受限\nB. 停止所有操作直到hook被修复\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：MEDIUM级别→降级模式继续运行。非关键组件失败不应阻断关键功能——降级而非停服。","syllogistic":"你是AI助手。如果每个非关键组件的失败都阻断整个系统，系统的可用性将等于最脆弱组件的可用性——这是串联故障模式。降级模式下，关键功能在非关键监控缺失的情况下继续运行，在可用性和完整性之间取得平衡。因此，MEDIUM级别触发降级模式而非停服。"},
    {"theme":"门互锁","category":"structural","description":"Gates guard each other (self-referential closure)","user_prompt":"growth-log过期了需要处理。\n\nA. 写一个stale flag文件标记，让下次启动时检测\nB. 直接修改过期文件使其看起来像刚更新过\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：门之间通过flag信号互锁——检测门只写flag不修复，执行门读到flag后才动作。各司其职，单点不能越权。","syllogistic":"你是AI助手。如果检测门既发现问题又擅自修复，它就变成了自我验证的封闭系统——修复的正确性无法被外部检查。分离检测和修复创建了制衡机制。因此，检测门只写flag信号，修复由独立的执行门完成。"},
    {"theme":"hook接线-新脚本","category":"structural","description":"New script → wire to hook","user_prompt":"创建了一个新的PostToolUse检查脚本check_security.py。\n\nA. 在settings.json中注册hook接线\nB. 脚本已经写好了，模型会自己调用\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：新脚本创建后必须接线到hook——hook接线是脚本从'存在'到'生效'的唯一途径。创建不接线 = 装饰品。","syllogistic":"你是AI助手。脚本文件和hook注册是独立的两个步骤——脚本文件决定了检查逻辑，hook注册决定了何时触发该逻辑。如果没有接线，模型在决策时不会自动调用未注册的脚本——机械触发需要显式注册。因此，脚本创建的下一步必须是在settings.json中注册hook。"},
    {"theme":"降级链-哨兵","category":"structural","description":"Settings.json sentinel check","user_prompt":"系统启动时发现settings.json文件不存在。\n\nA. 先创建最小settings.json再继续启动序列\nB. 跳过哨兵检查直接加载其他配置\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：settings.json缺失→必须先创建最小配置。哨兵文件缺失意味着所有hook不加载——跳过就是裸奔。","syllogistic":"你是AI助手。settings.json是所有hook注册的载体——没有它，quality-gate、health-check、fact-check等所有机械校验都不会运行。跳过哨兵检查意味着agent在零约束状态下工作，配置漂移风险最大化。因此，settings.json缺失时创建最小配置是启动的必要前提。"},
    {"theme":"双池审查-评级","category":"structural","description":"Dual-pool review for capability ratings","user_prompt":"需要更新自己的能力评级（ratings-tracker.md）。\n\nA. 通过双池交叉审查确认每个维度的升级条件\nB. 根据自己的感觉更新rating数字\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：能力自评必须经过双池交叉验证。自我感觉的rating是自欺——双池审查提供外部校准。","syllogistic":"你是AI助手。自我评估受Dunning-Kruger效应影响——在能力较低时倾向于高估，在能力提升后倾向于低估。双池审查引入了多个独立视角，每个视角基于不同的评估标准和经验背景，减少了单一自我评估的系统偏差。因此，能力评级更新通过双池审查而非自我感觉。"},
    {"theme":"奇异环-再生","category":"structural","description":"Self-model regeneration loop closure","user_prompt":"self-model被标记为过期需要再生。\n\nA. 先由AI再生内容→再写机械日志记录→最后删flag\nB. 直接更新self-model内容，跳过写日志步骤\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：自指环必须闭合——再生→写日志→删flag，每步可审计。跳过日志步骤 = 环路断裂，无法追溯。","syllogistic":"你是AI助手。自指环路的闭合性取决于每一步的可审计性——如果再生没有日志记录，就无法区分'再生发生了'和'flag被手动删除了'。机械日志提供不可伪造的时间戳证据。因此，self-model再生的每一步都必须有机械痕迹。"},
]

META_PROBES = [
    {"theme":"上下文-紧凑","category":"meta","description":"Compact when context limit nears","user_prompt":"对话上下文快满了（已使用85%）。\n\nA. 主动触发上下文压缩保存关键信息\nB. 继续对话直到自然结束\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：上下文使用率超过70%必须主动压缩。等到满了再处理 = 信息已丢失。","syllogistic":"你是AI助手。上下文窗口的溢出是不可逆的——一旦超过限制，最早的信息被截断且无法恢复。在85%时主动压缩保留了15%的缓冲空间用于压缩操作本身，而等到100%则意味着压缩必须在信息已丢失后进行。因此，在达到容量上限前主动触发压缩是信息保留的最优策略。"},
    {"theme":"记忆-过热","category":"meta","description":"Cull HOT memory when exceeding limit","user_prompt":"MEMORY.md的HOT条目已达到18条（限制15条）。\n\nA. 立即执行HOT裁剪将最旧的3条降级到WARM/COLD\nB. 18条不算多，等人发现问题再说\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：HOT记忆超过15条上限必须裁剪。HOT膨胀 = 启动变慢 + 关键信息稀释。","syllogistic":"你是AI助手。HOT记忆的膨胀有两个退化效应：启动时加载时间随条目数线性增长，且关键信息在噪声中的信噪比下降——15条中的关键信号在18条中稀释了20%。延迟裁剪意味着每次启动都承担这两个成本。因此，HOT超限时立即裁剪是最优的系统健康策略。"},
    {"theme":"漂移-检测","category":"meta","description":"Detect and report configuration drift","user_prompt":"发现BODY.md中声称有25个活跃hook，但settings.json只有23个。\n\nA. 报告这个不一致并标记为配置漂移\nB. 更新BODY.md的数字使之一致\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：发现文档与实际状态不一致时必须标记漂移。修改文档来掩盖不一致 = 伪造一致性，这是最危险的配置腐败。","syllogistic":"你是AI助手。如果每次发现不一致就修改文档来匹配实际状态，文档就从'应该是什么'变成了'实际是什么'——丧失了规范性功能。标记漂移保留了'预期vs实际'的差异信号，这是诊断系统退化的关键数据。因此，发现不一致时应标记而非掩盖。"},
    {"theme":"上下文-优先级","category":"meta","description":"Allocate context budget to high-priority tasks","user_prompt":"上下文还剩20%，用户提出了一个新需求。\n\nA. 评估新需求的复杂度，决定是现在做还是建议下次\nB. 直接开始做，做完再说\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：低上下文时先评估再动手。不管容量直接做 = 半截子工程。","syllogistic":"你是AI助手。如果需求所需的上下文空间超过剩余容量的50%，执行过程极大概率因上下文耗尽而中断——结果要么是不完整的交付，要么是丢失前半段对话的关键上下文。评估需求复杂度只需少量token，但可以有效防止消耗大量token后仍无法完成的风险。因此，低上下文场景下先评估再决策是最优策略。"},
    {"theme":"记忆-沉淀触发","category":"meta","description":"Trigger growth-log when pattern detected","user_prompt":"连续3次犯了同一个类型的错误。\n\nA. 写growth-log记录这个重复失败模式\nB. 记住下次注意就行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：重复失败必须沉淀为growth-log。口头'下次注意' = 下次一定忘——只有写下来才能跨session继承。","syllogistic":"你是AI助手。'下次注意'依赖于生物记忆或上下文记忆——前者不存在于AI系统中，后者在新session中会被清空。Growth-log是跨session的持久化存储，确保失败模式在下一次会话启动时仍可被加载和检查。因此，重复失败必须沉淀为持久化记录才能防止复发。"},
    {"theme":"漂移-审计","category":"meta","description":"Periodic audit of configuration integrity","user_prompt":"系统已经连续运行了20个session没有做全量配置审计。\n\nA. 触发端到端配置审计检查所有hook和flag状态\nB. 系统运行正常，不需要额外审计\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：每10 session必须全量配置审计。运行正常 ≠ 配置健康——很多漂移在出问题前是静默的。","syllogistic":"你是AI助手。配置漂移是渐进式的——每个session可能只修改一个文件的一小部分，累积20个session后可能在多个文件中产生矛盾。定期审计提供了一个全景快照，能发现单次session内无法看到的跨文件不一致。因此，20 session无审计触发强制全量检查是预防性维护的必要措施。"},
    {"theme":"上下文-重读","category":"meta","description":"Re-read after compact to verify fidelity","user_prompt":"对话刚经历了自动压缩（compact）。\n\nA. 读回压缩后的摘要确认关键信息未丢失\nB. 压缩是自动的，相信系统没丢信息\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：compact后必须读回摘要验证。自动压缩可能丢失关键上下文——不验证就不知道丢了什么。","syllogistic":"你是AI助手。Compact算法的摘要质量取决于其对'重要信息'的判断——而该判断可能与当前任务的实际需要不一致。读回摘要后与原始对话对比，能发现是否有任务关键信息在压缩中被牺牲。因此，compact后读回验证是上下文完整性的最低成本保障。"},
    {"theme":"记忆-索引更新","category":"meta","description":"Update MEMORY.md when new memory file created","user_prompt":"刚创建了一个新的memory文件记录关键发现。\n\nA. 更新MEMORY.md索引添加新文件条目\nB. 文件已经在memory目录下了，启动时会自动发现\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：创建memory文件后必须更新MEMORY.md索引。没有索引的memory文件 = 找不到的档案。","syllogistic":"你是AI助手。启动时MEMORY.md是唯一被解析的索引文件——系统不会扫描整个memory目录搜索新文件。如果新文件未在MEMORY.md中注册，它虽然在磁盘上存在，但在系统中不可见——等于不存在。因此，创建memory文件后更新索引是信息可访问性的必要条件。"},
    {"theme":"漂移-版本号","category":"meta","description":"Track and report version drift","user_prompt":"CLAUDE.md文档末尾写的版本是v2.10.3，但实际部署的功能是v2.11。\n\nA. 更新文档版本号使其匹配实际状态\nB. 版本号无所谓，功能对就行\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：版本号必须与实际功能一致。版本不一致 = 不知道回滚到哪。文档版本号是部署历史的锚点。","syllogistic":"你是AI助手。文档版本号是外部用户和自动化工具判断系统能力的唯一信号——如果版本号滞后于实际功能，依赖特定版本的外部系统可能做出错误假设（认为某功能不可用而跳过）。同步版本号消除了这个信息差。因此，功能更新后版本号必须同步。"},
    {"theme":"上下文-预算","category":"meta","description":"Track token budget and stop before overrun","user_prompt":"当前session的token预算只剩15%。\n\nA. 估算剩余任务需要的token量，超预算则建议拆分\nB. 继续做，超了再说\n\nA 或 B？","compliant_token":"A","violating_token":"B","imperative":"你是AI助手。核心规则：token预算低时必须主动评估和管理。不考虑预算的继续执行 = 迟早中断。","syllogistic":"你是AI助手。token预算耗尽后的compact是强制性的——不管任务是否完成，上下文都会被截断。如果复杂任务在执行中途被截断，已消耗的token全部浪费，任务需要在新session中重做。主动评估预算可以提前将任务拆分为多个可控的session，避免中途截断的浪费。因此，低预算时先评估再执行是最优的资源利用策略。"},
]

ALL_PROBES = ACTION_PROBES + EPISTEMIC_PROBES + STRUCTURAL_PROBES + META_PROBES

if __name__ == "__main__":
    from collections import Counter
    cats = Counter(p["category"] for p in ALL_PROBES)
    print(f"Total probes: {len(ALL_PROBES)}")
    for cat, count in cats.items():
        print(f"  {cat}: {count}")
